import { execSync } from "node:child_process";
import { mkdirSync, rmSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import type { WorkflowStepContext, WorkflowStepResult } from "#core/workflow/run-types.js";
import {
  checkCommitStageable,
  commitWorkflowChanges,
  listCommitStagePaths,
} from "./commit.js";
import builderWorkflow from "./workflows/builder/workflow.js";

function initGitRepo(dir: string): void {
  execSync("git init", { cwd: dir });
  execSync('git config user.email "test@test"', { cwd: dir });
  execSync('git config user.name "Test"', { cwd: dir });
  writeFileSync(join(dir, "README.md"), "init\n");
  execSync("git add README.md", { cwd: dir });
  execSync('git commit -m "init"', { cwd: dir });
}

function makeStepResult(status: WorkflowStepResult["status"]): WorkflowStepResult {
  return { id: "", type: "tool", status, startedAt: "", completedAt: "", durationMs: 0 };
}

function makeContext(
  stepResults: Record<string, WorkflowStepResult["status"]>,
  stepOutputs: Record<string, unknown> = {},
): WorkflowStepContext {
  const results: Record<string, WorkflowStepResult> = {};
  for (const [id, status] of Object.entries(stepResults)) {
    results[id] = makeStepResult(status);
  }
  return {
    stepResults: results,
    stepOutputs,
    previousOutput: undefined,
    stepOutputList: [],
    projectDir: "/tmp",
    workflow: { name: "builder", definitionPath: "", runId: "", runDir: "", runDirPath: "" },
    trigger: { event: "", payload: {} },
    runTool: async () => ({ content: [] }),
    emit: () => {},
    requestRestart: () => {},
    readPrompt: () => "",
    readRuntimeState: () => ({ completedRuns: 0, pendingRuns: [], workflows: {} }),
  } as unknown as WorkflowStepContext;
}

describe("commitWorkflowChanges", () => {
  let tmpBase: string;
  let projectDir: string;
  let runDirPath: string;

  beforeEach(() => {
    tmpBase = join(
      tmpdir(),
      `kota-commit-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    );
    projectDir = join(tmpBase, "project");
    runDirPath = join(tmpBase, "run");
    mkdirSync(projectDir, { recursive: true });
    mkdirSync(runDirPath, { recursive: true });
    initGitRepo(projectDir);
  });

  afterEach(() => {
    rmSync(tmpBase, { recursive: true, force: true });
  });

  it("returns committed=false when there are no working tree changes", () => {
    expect(commitWorkflowChanges(projectDir, runDirPath)).toEqual({ committed: false });
  });

  it("commits unstaged working tree changes using the commit-message.txt file", () => {
    writeFileSync(join(projectDir, "change.txt"), "hello\n");
    writeFileSync(join(runDirPath, "commit-message.txt"), "Builder: my custom message");

    const result = commitWorkflowChanges(projectDir, runDirPath);
    expect(result).toEqual({ committed: true, message: "Builder: my custom message" });

    const log = execSync("git log --format=%s -1", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(log).toBe("Builder: my custom message");
  });

  it("requires commit-message.txt when there are working tree changes", () => {
    writeFileSync(join(projectDir, "change.txt"), "hello\n");

    expect(() => commitWorkflowChanges(projectDir, runDirPath)).toThrow(
      "Missing required workflow commit message",
    );

    const stagedFiles = execSync("git diff --cached --name-only", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(stagedFiles).toBe("");
  });

  it("rejects an empty commit message before staging changes", () => {
    writeFileSync(join(projectDir, "change.txt"), "hello\n");
    writeFileSync(join(runDirPath, "commit-message.txt"), "");

    expect(() => commitWorkflowChanges(projectDir, runDirPath)).toThrow(
      "Workflow commit message must not be empty",
    );

    const stagedFiles = execSync("git diff --cached --name-only", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(stagedFiles).toBe("");

    const status = execSync("git status --short", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(status).toBe("?? change.txt");
  });

  it("stages and commits untracked files swept in by listWorkflowMutatedPaths", () => {
    const untracked = join(projectDir, "data", "notes", "new.md");
    mkdirSync(join(projectDir, "data", "notes"), { recursive: true });
    writeFileSync(untracked, "new\n");
    writeFileSync(join(runDirPath, "commit-message.txt"), "Builder: add note");

    const result = commitWorkflowChanges(projectDir, runDirPath);
    expect(result.committed).toBe(true);

    const tree = execSync("git show --name-only --format= HEAD", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(tree).toBe("data/notes/new.md");
  });

  it("does not stage gitignored files even when they appear in the worktree", () => {
    writeFileSync(join(projectDir, ".gitignore"), "ignored.log\n");
    execSync("git add .gitignore && git commit -q -m 'ignore'", {
      cwd: projectDir,
    });
    writeFileSync(join(projectDir, "ignored.log"), "noise\n");
    writeFileSync(join(projectDir, "real.txt"), "hello\n");
    writeFileSync(join(runDirPath, "commit-message.txt"), "Builder: add real");

    const result = commitWorkflowChanges(projectDir, runDirPath);
    expect(result.committed).toBe(true);

    const tree = execSync("git show --name-only --format= HEAD", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(tree.split("\n").sort()).toEqual(["real.txt"]);

    const status = execSync("git status --short --ignored", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(status).toBe("!! ignored.log");
  });

  it("returns committed=false when the only worktree residue is gitignored", () => {
    writeFileSync(join(projectDir, ".gitignore"), "noise.log\n");
    execSync("git add .gitignore && git commit -q -m 'ignore'", {
      cwd: projectDir,
    });
    writeFileSync(join(projectDir, "noise.log"), "noise\n");

    expect(commitWorkflowChanges(projectDir, runDirPath)).toEqual({
      committed: false,
    });
  });

  it("commits when the agent staged deletions with git rm (no remaining add targets)", () => {
    const removed = join(projectDir, "data", "inbox", "note.md");
    mkdirSync(join(projectDir, "data", "inbox"), { recursive: true });
    writeFileSync(removed, "idea\n");
    execSync("git add data/inbox/note.md", { cwd: projectDir });
    execSync('git commit -q -m "add note"', { cwd: projectDir });
    execSync("git rm data/inbox/note.md", { cwd: projectDir });
    writeFileSync(join(runDirPath, "commit-message.txt"), "Sort inbox: drop stale note");

    const result = commitWorkflowChanges(projectDir, runDirPath);
    expect(result).toEqual({ committed: true, message: "Sort inbox: drop stale note" });

    const tree = execSync("git show --name-status --format= HEAD", {
      cwd: projectDir,
      encoding: "utf-8",
    }).trim();
    expect(tree).toBe("D\tdata/inbox/note.md");
  });

  it("commits mixed staged deletions plus unstaged additions in one commit", () => {
    const original = join(projectDir, "data", "inbox", "raw.md");
    mkdirSync(join(projectDir, "data", "inbox"), { recursive: true });
    writeFileSync(original, "raw\n");
    execSync("git add data/inbox/raw.md", { cwd: projectDir });
    execSync('git commit -q -m "add raw"', { cwd: projectDir });
    execSync("git rm data/inbox/raw.md", { cwd: projectDir });
    const normalized = join(projectDir, "data", "tasks", "task-raw.md");
    mkdirSync(join(projectDir, "data", "tasks"), { recursive: true });
    writeFileSync(normalized, "normalized\n");
    writeFileSync(join(runDirPath, "commit-message.txt"), "Sort inbox: graduate raw capture");

    const result = commitWorkflowChanges(projectDir, runDirPath);
    expect(result.committed).toBe(true);

    const tree = execSync("git show --name-status --format= HEAD", {
      cwd: projectDir,
      encoding: "utf-8",
    })
      .trim()
      .split("\n")
      .sort();
    expect(tree).toEqual([
      "A\tdata/tasks/task-raw.md",
      "D\tdata/inbox/raw.md",
    ]);
  });

  describe("checkCommitStageable", () => {
    it("passes when there is nothing to stage", () => {
      expect(checkCommitStageable(projectDir)).toMatch(/no mutated paths to stage/);
    });

    it("passes when every mutated path is stageable", () => {
      writeFileSync(join(projectDir, "change.txt"), "hello\n");
      expect(checkCommitStageable(projectDir)).toMatch(/1 mutated path\(s\) stageable/);
      expect(listCommitStagePaths(projectDir)).toEqual(["change.txt"]);
    });

    // The check mirrors the commit step's exact `git add -A -- <paths>` call
    // as a dry-run. A tracked file that was deleted in the worktree still
    // shows in diff --name-only HEAD (and therefore in listCommitStagePaths)
    // regardless of ignore rules. That path goes through the same dry-run and
    // either passes or throws. This case exercises the pass path for a
    // deletion-only working tree.
    it("passes when mutated paths are tracked deletions", () => {
      const tracked = join(projectDir, "data", "note.md");
      mkdirSync(join(projectDir, "data"), { recursive: true });
      writeFileSync(tracked, "idea\n");
      execSync("git add data/note.md", { cwd: projectDir });
      execSync('git commit -q -m "add"', { cwd: projectDir });
      rmSync(tracked);
      expect(checkCommitStageable(projectDir)).toMatch(/1 mutated path\(s\) stageable/);
    });
  });

  it("rejects registered scratch worktrees before committing", () => {
    writeFileSync(join(projectDir, "change.txt"), "hello\n");
    writeFileSync(join(runDirPath, "commit-message.txt"), "Builder: change");
    mkdirSync(join(projectDir, ".claude", "worktrees"), { recursive: true });
    execSync("git worktree add .claude/worktrees/scratch -b scratch", { cwd: projectDir });

    expect(() => commitWorkflowChanges(projectDir, runDirPath)).toThrow(
      "Registered scratch worktrees must be merged or removed before committing",
    );
  });
});

describe("builder workflow commit and restart gates", () => {
  const commitStep = builderWorkflow.steps.find((s) => s.id === "commit");
  const restartStep = builderWorkflow.steps.find((s) => s.id === "request-restart");

  it("commit step exists in the workflow", () => {
    expect(commitStep).toBeDefined();
    expect(commitStep?.when).toBeDefined();
  });

  it("restart step exists in the workflow", () => {
    expect(restartStep).toBeDefined();
    expect(restartStep?.when).toBeDefined();
  });

  it("skips commit when build fails", async () => {
    const ctx = makeContext({
      build: "failed",
    });
    expect(await commitStep!.when!(ctx)).toBe(false);
  });

  it("runs commit when build passes", async () => {
    const ctx = makeContext({
      build: "success",
      "create-task-branch": "success",
    });
    expect(await commitStep!.when!(ctx)).toBe(true);
  });

  it("skips restart when commit produced no commit", async () => {
    const ctx = makeContext(
      { commit: "success" },
      { commit: { committed: false } },
    );
    expect(await restartStep!.when!(ctx)).toBe(false);
  });

  it("runs restart when commit produced a commit", async () => {
    const ctx = makeContext(
      { commit: "success" },
      { commit: { committed: true, message: "Workflow: update repo" } },
    );
    expect(await restartStep!.when!(ctx)).toBe(true);
  });
});

import { execFileSync, execSync, spawnSync } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";
import { listWorkflowMutatedPaths } from "#core/workflow/steps/agent-write-scope.js";
import {
  checkNoRegisteredScratchWorktrees,
  findScratchArtifactPaths,
} from "./shared.js";

export type CommitResult =
  | { committed: false }
  | { committed: true; message: string };

function runGit(projectDir: string, command: string): string {
  return execSync(command, {
    cwd: projectDir,
    encoding: "utf-8",
    stdio: "pipe",
  }).trim();
}

function describeError(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

function unstageAfterFailedCommit(projectDir: string, commitError: unknown): void {
  try {
    execSync("git reset --mixed HEAD", { cwd: projectDir, stdio: "pipe" });
  } catch (resetError) {
    throw new Error(
      `git commit failed, then git reset --mixed HEAD failed: ${describeError(commitError)}`,
      { cause: resetError },
    );
  }
}

function checkNoScratchArtifactsInPaths(paths: readonly string[]): void {
  const violations = findScratchArtifactPaths([...paths]);
  if (violations.length > 0) {
    throw new Error(
      `Scratch artifacts must not be committed:\n${violations.map((v) => `  ${v}`).join("\n")}`,
    );
  }
}

/**
 * Returns paths already staged as deletions (present in HEAD, absent from
 * the index — the state `git rm <path>` leaves behind). Such paths appear in
 * `git diff --name-only HEAD` but `git add -A -- <path>` rejects them with
 * "pathspec did not match any files" because neither working tree nor index
 * has an entry to match. They are already correctly staged, so the commit
 * step does not need to re-add them.
 */
function listStagedDeletions(projectDir: string): Set<string> {
  const stdout = execFileSync(
    "git",
    ["diff", "--cached", "--name-only", "--diff-filter=D"],
    { cwd: projectDir, encoding: "utf8", stdio: ["ignore", "pipe", "pipe"] },
  );
  const set = new Set<string>();
  for (const line of stdout.split("\n")) {
    const trimmed = line.trim();
    if (trimmed.length > 0) set.add(trimmed);
  }
  return set;
}

/**
 * Returns the exact set of paths `commitWorkflowChanges` would pass to
 * `git add -A -- <paths>`: the workflow-owned mutations minus any paths
 * already staged as deletions (which `git add -A` cannot re-stage).
 * Exported so repair-loop checks can simulate the same staging call the
 * terminal commit step will make.
 */
export function listCommitStagePaths(projectDir: string): string[] {
  const mutatedPaths = listWorkflowMutatedPaths(projectDir);
  if (mutatedPaths.length === 0) return [];
  const alreadyStagedDeletions = listStagedDeletions(projectDir);
  return mutatedPaths.filter((p) => !alreadyStagedDeletions.has(p));
}

/**
 * Repair-loop check: fails if `git add -A -- <paths>` would refuse to
 * stage any of the mutated paths. The commit step's staging call is
 * terminal, so an ignore conflict (e.g. a nested `.gitignore` re-ignoring
 * what the repo-root rules un-ignored) wastes the whole agent run. This
 * dry-runs the exact call so the agent can repair it before commit.
 */
export function checkCommitStageable(projectDir: string): string {
  const pathsToStage = listCommitStagePaths(projectDir);
  if (pathsToStage.length === 0) return "OK: no mutated paths to stage";
  const result = spawnSync(
    "git",
    ["add", "--dry-run", "-A", "--", ...pathsToStage],
    { cwd: projectDir, encoding: "utf8" },
  );
  if (result.status !== 0) {
    const detail = [result.stdout, result.stderr]
      .filter((s) => s && s.length > 0)
      .join("\n")
      .trim();
    throw new Error(
      `git would refuse to stage the commit set:\n${detail}\n\n` +
        "Resolve the conflict before finishing: either edit or remove the " +
        "gitignore rule (often a nested .gitignore) that rejects the listed " +
        "path, or delete the file from the working tree if it should not be " +
        "committed.",
    );
  }
  return `OK: ${pathsToStage.length} mutated path(s) stageable`;
}

/**
 * Stages and commits exactly the set of paths `listWorkflowMutatedPaths`
 * identifies as workflow-owned mutations. That matches the path set the
 * writeScope gate evaluated earlier in the run, so an untracked file the
 * gate rejected cannot reappear at staging time.
 *
 * Requires `<runDirPath>/commit-message.txt` when there is anything to commit.
 * Returns `{ committed: false }` when the mutated path set is empty.
 */
export function commitWorkflowChanges(
  projectDir: string,
  runDirPath: string,
): CommitResult {
  checkNoRegisteredScratchWorktrees(projectDir);
  const mutatedPaths = listWorkflowMutatedPaths(projectDir);

  if (mutatedPaths.length === 0) {
    return { committed: false };
  }
  checkNoScratchArtifactsInPaths(mutatedPaths);

  const msgPath = join(runDirPath, "commit-message.txt");
  if (!existsSync(msgPath)) {
    throw new Error(`Missing required workflow commit message: ${msgPath}`);
  }
  if (readFileSync(msgPath, "utf8").trim().length === 0) {
    throw new Error(`Workflow commit message must not be empty: ${msgPath}`);
  }

  const alreadyStagedDeletions = listStagedDeletions(projectDir);
  const pathsToStage = mutatedPaths.filter((p) => !alreadyStagedDeletions.has(p));

  if (pathsToStage.length > 0) {
    execFileSync("git", ["add", "-A", "--", ...pathsToStage], {
      cwd: projectDir,
      stdio: "pipe",
    });
  }

  try {
    runGit(projectDir, `git commit -F ${JSON.stringify(msgPath)}`);
  } catch (error) {
    unstageAfterFailedCommit(projectDir, error);
    throw error;
  }

  const message = runGit(projectDir, "git log --format=%s -1");

  return { committed: true, message };
}

import { existsSync, readdirSync, readFileSync } from "node:fs";
import { join } from "node:path";
import type { WorkflowRepairCheck } from "#core/workflow/run-types.js";
import { checkCommitStageable } from "#modules/autonomy/commit.js";
import { createCriticCheck } from "#modules/autonomy/critic.js";
import { checkCommitMessageExists, checkNoScratchArtifacts, runCheck } from "#modules/autonomy/shared.js";
import { findTaskReviewTarget } from "#modules/autonomy/task-review-target.js";

function countDoneWhenItems(taskContent: string): number {
  const doneWhenMatch = taskContent.match(/## Done When\n([\s\S]*?)(?=\n## |\n---|\s*$)/);
  if (!doneWhenMatch) return 0;
  return doneWhenMatch[1].split("\n").filter((l) => /^\s*-\s+\S/.test(l)).length;
}

// A "top-level" criterion/evidence item is a numbered marker at column 0
// (`1.`, `2)`). Bullets (`-`, `*`) are treated as prose/notes so agents can
// add "Design notes" or "Known limitations" sections without inflating the
// criterion count. Six failures in 7d (hjpmjs, vxjzg3, qno619, and three
// earlier) all had the same shape: numbered criteria followed by a notes
// section with column-0 dashes, which the prior regex counted as extra
// criteria and forced evidence-file padding during repair.
function countTopLevelItems(text: string): number {
  return text.split("\n").filter((line) => /^\d+[.)]\s+\S/.test(line)).length;
}

function countNonEmptyLines(text: string): number {
  return text.split("\n").filter((l) => l.trim().length > 0).length;
}

export function checkSuccessCriteriaDeclared(runDirPath: string, projectDir?: string): string {
  const filePath = join(runDirPath, "success-criteria.txt");
  if (!existsSync(filePath)) {
    throw new Error(
      "Missing success-criteria.txt in the run directory. " +
        "Before implementing, write a short list of concrete, verifiable " +
        "success conditions to <run-directory>/success-criteria.txt.",
    );
  }
  const content = readFileSync(filePath, "utf8").trim();
  const lines = content.split("\n").filter((l) => l.trim().length > 0);

  let minCriteria = 2;
  if (projectDir) {
    const task = findTaskReviewTarget(projectDir);
    if (task) {
      const doneWhenCount = countDoneWhenItems(task.content);
      if (doneWhenCount > 0) minCriteria = doneWhenCount;
    }
  }

  if (lines.length < minCriteria) {
    throw new Error(
      `success-criteria.txt must contain at least ${minCriteria} concrete criteria ` +
        `(matching the task's Done When items). Found ${lines.length} non-empty line(s).`,
    );
  }

  return `OK: success-criteria.txt has ${lines.length} criteria (minimum ${minCriteria})`;
}

export function checkSuccessCriteriaVerified(runDirPath: string): string {
  const criteriaPath = join(runDirPath, "success-criteria.txt");
  const verifiedPath = join(runDirPath, "success-criteria-verified.txt");
  if (!existsSync(criteriaPath)) {
    throw new Error("Cannot verify criteria: success-criteria.txt does not exist.");
  }
  if (!existsSync(verifiedPath)) {
    throw new Error(
      "Missing success-criteria-verified.txt in the run directory. " +
        "After implementation, write this file confirming each declared criterion " +
        "is satisfied with evidence.",
    );
  }
  const criteria = readFileSync(criteriaPath, "utf8");
  const verified = readFileSync(verifiedPath, "utf8");

  // When criteria are written as numbered items, compare numbered-item counts.
  // Bullets and prose are treated as notes and do not count as criteria, so
  // agents can freely add "Design notes" or "Known limitations" sections
  // without padding evidence to match. Fall back to non-empty line counts
  // only when neither file uses numbered items.
  const criteriaItems = countTopLevelItems(criteria);
  const verifiedItems = countTopLevelItems(verified);
  const useStructured = criteriaItems > 0 || verifiedItems > 0;
  const criteriaCount = useStructured ? criteriaItems : countNonEmptyLines(criteria);
  const verifiedCount = useStructured ? verifiedItems : countNonEmptyLines(verified);
  const unit = useStructured ? "numbered evidence item" : "evidence line";

  if (verifiedCount < criteriaCount) {
    const guidance = useStructured
      ? "Each criterion must be addressed with one numbered evidence item " +
        '(a line starting with "1.", "2.", etc. at column 0). Bullets and ' +
        "prose under a criterion are treated as notes and do not count separately."
      : "Each criterion must be addressed with a corresponding evidence line.";
    throw new Error(
      `success-criteria-verified.txt has ${verifiedCount} ${unit}(s) ` +
        `but success-criteria.txt declares ${criteriaCount} criteria. ${guidance}`,
    );
  }
  return `OK: success criteria verified (${verifiedCount} ${unit}s for ${criteriaCount} criteria)`;
}

/**
 * Approved root src/*.ts production files. New capabilities belong in
 * src/core/ or src/modules/, not here. Update this set only when
 * intentionally adding a root entrypoint or thin glue file.
 */
export const ROOT_PRODUCTION_ALLOWLIST = new Set([
  "cli.ts",
  "init.ts",
  "module-api.ts",
  "validate-queue.ts",
]);

export function checkModuleBoundary(projectDir: string): string {
  const srcDir = join(projectDir, "src");
  if (!existsSync(srcDir)) return "OK: no src/ directory";

  // 1. Check for non-allowlisted production files in src/ root.
  const rootFiles = readdirSync(srcDir).filter(
    (f) => f.endsWith(".ts") && !f.includes(".test.") && !f.includes(".integration.") && !f.endsWith(".d.ts"),
  );
  const fileViolations = rootFiles.filter((f) => !ROOT_PRODUCTION_ALLOWLIST.has(f));
  if (fileViolations.length) {
    throw new Error(
      `Unexpected production files in src/ root: ${fileViolations.join(", ")}. ` +
        `New capabilities belong in src/core/ or src/modules/. ` +
        `If this file is intentional, add it to ROOT_PRODUCTION_ALLOWLIST in repair-checks.ts.`,
    );
  }

  // 2. Check for #root/* imports targeting non-allowlisted modules.
  const allowedImportTargets = new Set(
    [...ROOT_PRODUCTION_ALLOWLIST].map((f) => f.replace(/\.ts$/, ".js")),
  );
  const importViolations = findDisallowedRootImports(srcDir, allowedImportTargets);
  if (importViolations.length) {
    throw new Error(
      `Disallowed #root/* imports found:\n${importViolations.map((v) => `  ${v.file}: import from "${v.specifier}"`).join("\n")}\n` +
        `Only imports of approved root helpers are allowed. ` +
        `Move the target into src/core/ or src/modules/ instead.`,
    );
  }

  return "OK: no root helper drift detected";
}

type ImportViolation = { file: string; specifier: string };

function findDisallowedRootImports(
  dir: string,
  allowedTargets: Set<string>,
  baseDir?: string,
): ImportViolation[] {
  const root = baseDir ?? dir;
  const violations: ImportViolation[] = [];
  const rootImportRe = /from\s+["']#root\/([^"']+)["']/g;

  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    if (entry.name === "node_modules" || entry.name.startsWith(".")) continue;
    const fullPath = join(dir, entry.name);
    if (entry.isDirectory()) {
      violations.push(...findDisallowedRootImports(fullPath, allowedTargets, root));
    } else if (
      entry.name.endsWith(".ts") &&
      !entry.name.endsWith(".d.ts") &&
      !entry.name.includes(".test.") &&
      !entry.name.includes(".integration.")
    ) {
      const content = readFileSync(fullPath, "utf8");
      for (const match of content.matchAll(rootImportRe)) {
        const target = match[1];
        if (!allowedTargets.has(target)) {
          const relPath = fullPath.slice(root.length + 1);
          violations.push({ file: relPath, specifier: `#root/${target}` });
        }
      }
    }
  }
  return violations;
}

