  id: "inspect-watchlist",
  type: "code",
  exposeOutputToAgent: true,
  run: ({ projectDir }) => {
    const file = readWatchlist(projectDir);
    return {
      entries: file.entries.map(summarizeWatchlistEntry),
      updateReportPath: "watchlist-updates.json",
    };
  },
});

